#!/bin/bash
# check-repo-hygiene.sh — Detect binary files, generated code, and build artifacts
# in staged changes. Use as a pre-commit hook or CI check.
#
# Install as pre-commit hook:
#   cp scripts/check-repo-hygiene.sh .git/hooks/pre-commit
#   chmod +x .git/hooks/pre-commit

set -e

ERRORS=0
MAX_BINARY_SIZE=10240  # 10 KB

echo "Checking repo hygiene..."

# 1. Check for staged bindings.rs (auto-generated, should never be committed)
BINDINGS=$(git diff --cached --name-only --diff-filter=ACM | grep 'bindings\.rs$' || true)
if [ -n "$BINDINGS" ]; then
    echo "ERROR: Generated bindings.rs files should not be committed:"
    echo "$BINDINGS" | sed 's/^/  /'
    echo "  These are auto-generated by cargo-component. Add to .gitignore."
    ERRORS=$((ERRORS + 1))
fi

# 2. Check for staged .wasm files
WASM=$(git diff --cached --name-only --diff-filter=ACM | grep '\.wasm$' || true)
if [ -n "$WASM" ]; then
    echo "ERROR: .wasm files should not be committed (build artifacts):"
    echo "$WASM" | sed 's/^/  /'
    ERRORS=$((ERRORS + 1))
fi

# 3. Check for staged .raw files
RAW=$(git diff --cached --name-only --diff-filter=ACM | grep '\.raw$' || true)
if [ -n "$RAW" ]; then
    echo "ERROR: .raw fixture files should not be committed (generate programmatically):"
    echo "$RAW" | sed 's/^/  /'
    echo "  See .agent/kf/code_styleguides/repo-hygiene.md for fixture generation patterns."
    ERRORS=$((ERRORS + 1))
fi

# 4. Check for large binary files (> 10 KB)
STAGED=$(git diff --cached --name-only --diff-filter=ACM)
if [ -n "$STAGED" ]; then
    while IFS= read -r file; do
        if [ -f "$file" ]; then
            SIZE=$(wc -c < "$file" 2>/dev/null | tr -d ' ')
            if [ "$SIZE" -gt "$MAX_BINARY_SIZE" ]; then
                # Check if file is binary (contains null bytes)
                if file "$file" | grep -qE 'binary|data|image|font'; then
                    echo "ERROR: Binary file too large (${SIZE} bytes > ${MAX_BINARY_SIZE}): $file"
                    ERRORS=$((ERRORS + 1))
                fi
            fi
        fi
    done <<< "$STAGED"
fi

# 5. Check for files with "Auto-generated" or "Do not edit" headers
AUTOGEN=$(git diff --cached --name-only --diff-filter=ACM | while IFS= read -r file; do
    if [ -f "$file" ] && head -5 "$file" 2>/dev/null | grep -qiE 'auto-generated|do not edit'; then
        echo "$file"
    fi
done)
if [ -n "$AUTOGEN" ]; then
    echo "WARNING: Files with 'Auto-generated' headers staged (verify they should be committed):"
    echo "$AUTOGEN" | sed 's/^/  /'
fi

if [ "$ERRORS" -gt 0 ]; then
    echo ""
    echo "FAILED: $ERRORS repo hygiene violation(s) found."
    echo "See .agent/kf/code_styleguides/repo-hygiene.md for policies."
    exit 1
fi

echo "OK: No repo hygiene violations."
